INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('b6d822fd-6c5f-5762-9f46-fbc679313184', 'ec7d466c-acfd-4fc7-a77e-9a474040833b', 'The fourth month of the year is ___.', '一年中的第四個月是四月。', 'April', 'March', 'May', 'June', 'April 為專有名詞，代表四月。', 'April → 四月 (記住 A 開頭的月份是 April)', '2026-07-06 14:40:07', '2026-07-06 14:40:07'),
('61d7fbc0-e1f3-5273-95de-4bafcf5ec15c', '6de21873-0b3a-4a85-96c8-30ec0e0d91ea', '___ am twelve years old.', '我十二歲。', 'I', 'He', 'She', 'It', 'I 是第一人稱單數代名詞。', '記住 I 永遠要大寫。', '2026-07-05 11:48:08', '2026-07-05 11:48:08'),
('15429e94-3f59-57e8-a08b-8b7580ad23c0', '0c81c4d7-077d-46ec-b6bc-a975304fa7ad', 'The influence of this new technology has spread ___ the entire globe.', '這項新技術的影響力已遍及全球。', 'across', 'beside', 'against', 'above', 'cross (十字/橫越) + a- (在...之上) → across (橫跨/遍及)', '想像你在地圖上畫一條線，橫向劃過 (across) 整個世界。', '2026-07-06 17:20:36', '2026-07-06 17:20:36'),
('38ffedf0-705a-5379-a88c-5844137c3620', '23652fd2-f845-40ef-888c-512c2874d46a', 'The kind-hearted stranger was like an ___ to the lost child, guiding him safely back to his parents.', '那位心地善良的陌生人對那個迷路的孩子來說就像是一位天使，引導他安全地回到父母身邊。', 'angel', 'artist', 'officer', 'athlete', 'angel 源自希臘語 ''angelos''，意為「使者」(messenger)。', '想像一個帶著翅膀、傳達神聖訊息的使者，那就是 angel。', '2026-07-06 21:15:24', '2026-07-06 21:15:24'),
('efc124c6-d910-5b35-a500-5c0852ceeed0', '09595184-cdac-421c-84bf-2f687758156e', 'The crowd broke into enthusiastic ___ when the singer finally appeared on stage.', '當歌手終於登上舞台時，人群爆發出熱烈的鼓掌。', 'applause', 'laughter', 'silence', 'protest', '字根解析：ap- (朝向) + plaud (拍手) → 拍手聲、喝采。', '想像大家拍手 clap 拍向舞台 ap，就是 applause。', '2026-07-06 22:59:51', '2026-07-06 22:59:51'),
('a04285f7-6d54-56bb-a71f-55cc21885b30', '3cb1ec5a-7337-456f-bd4e-61144f390f5b', 'This apple is ___ sweet ___ that one.', '這個蘋果跟那個一樣甜。', 'as', 'very', 'too', 'quite', 'as...as 結構用來表示「跟...一樣地」。', 'as...as → 跟...一樣', '2026-07-06 14:53:47', '2026-07-06 14:53:47'),
('90413d03-2844-51b3-9961-31e271dc5d64', 'be8e6cee-5789-4600-baff-58002526f10c', 'She ___ a doctor who works in the hospital.', '她是一位在醫院工作的醫生。', 'is', 'has', 'wants', 'makes', 'be 用來表示身分或狀態。', '表示「是」的身分，選 be。', '2026-07-05 13:54:38', '2026-07-05 13:54:38'),
('b6be93cd-d927-5af3-9984-912527abb484', 'c5a6bb6c-11be-4f15-9ea7-f6b983edff63', 'The sculpture represents the very ___ of the subject.', '這座雕塑展現了主體的本質。', 'being', 'color', 'shape', 'size', 'be (存在) + ing (名詞字尾) → 存在、生命體、本質。', '想像「being」就是「正在存在著的狀態」→ 存在、生命。', '2026-07-05 14:01:43', '2026-07-05 14:01:43'),
('7e50770b-e3d5-5321-a8e4-3994cee69f18', 'c92024c4-5535-41cd-b587-d5c018f7df4b', 'You can ___ these books by their color.', '你可以根據顏色來分類這些書。', 'class', 'find', 'make', 'read', 'class 源自拉丁語 classis，意指「群體」或「等級」。', '把東西分等級(class)是很重要的步驟。', '2026-07-07 04:05:27', '2026-07-07 04:05:27'),
('2443496b-9291-5184-9531-ba8656d61cb8', 'd8b3ec22-92b0-4e3d-bb59-a2558ec8f82c', 'My uncle is a ___; he works in a big hospital.', '我的叔叔是一位醫生；他在一家大醫院工作。', 'doctor', 'pilot', 'baker', 'driver', 'doc- 來自拉丁文，意思是教導或學習。', 'doctor 唸起來像多考，醫生需要通過很多考試。', '2026-07-07 04:57:00', '2026-07-07 04:57:00'),
('d387209e-f464-523c-be6e-228640d886a8', '7f4e490e-1e89-4344-ab36-64d368deaf80', 'I have an English ___ tomorrow.', '我明天有一個英文考試。', 'exam', 'game', 'song', 'gift', 'exam 源於拉丁語 examinare，代表檢查或測試。', 'exam 唸起來像「一檢查」→ 考試就是要檢查你的知識。', '2026-07-07 04:58:23', '2026-07-07 04:58:23'),
('261544e3-cbec-50e6-98fa-5e0a029490b8', 'c8f5ae6e-0be6-420b-a927-4ab8a3519a32', 'After the long journey, ___ finally arrived at the destination feeling exhausted but happy.', '長途跋涉之後，我們終於抵達了目的地，感到精疲力竭但很開心。', 'we', 'she', 'it', 'you', '第一人稱複數主格，代表說話者所屬的群體。', '想像「我」加入了「大家」，大家就變成了 we。', '2026-07-06 11:04:30', '2026-07-06 11:04:30');
